SESSION_TTL_SECONDS = 3600
CACHE_TTL_SECONDS = 300


def generate_session_id():
    return str(uuid.uuid4())


def session_key(session_id):
    return f"session:{session_id}"


def cache_key(prefix, *args, **kwargs):
    raw = prefix + ":" + ":".join(map(str, args))
    if kwargs:
        raw += ":" + ":".join(f"{k}={v}" for k, v in sorted(kwargs.items()))
    return f"cache:{raw}"


def create_session(user_id, extra_data=None):
    session_id = generate_session_id()
    data = {
        "user_id": user_id,
        "created_at": datetime.utcnow().isoformat(),
        "extra_data": extra_data or {},
    }
    redis_client.set(session_key(session_id), json.dumps(data), ex=SESSION_TTL_SECONDS)
    return session_id


def get_session(session_id):
    raw = redis_client.get(session_key(session_id))
    if not raw:
        return None
    try:
        return json.loads(raw)
    except json.JSONDecodeError:
        return None


def update_session(session_id, data):
    redis_client.set(session_key(session_id), json.dumps(data), ex=SESSION_TTL_SECONDS)


def delete_session(session_id):
    redis_client.delete(session_key(session_id))


def cached_query(prefix, ttl=CACHE_TTL_SECONDS):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            key = cache_key(prefix, *args, **kwargs)
            cached_value = redis_client.get(key)
